1	/** A live cell on the infinite grid, identified by its [x, y] coordinates. */
2	export type Cell = [number, number];
3	
4	/**
5	 * Computes the next generation of live cells according to Conway's Game of Life rules.
6	 * Uses a sparse representation: only live cells are listed; cells not listed are dead.
7	 *
8	 * @param liveCells - Coordinates of currently live cells (order is not significant)
9	 * @returns Coordinates of cells that will be live in the next generation
10	 */
11	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
12	  [-1, -1], [0, -1], [1, -1],
13	  [-1,  0],          [1,  0],
14	  [-1,  1], [0,  1], [1,  1],
15	];
16	
17	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
18	
19	const survives = (isAlive: boolean, neighborCount: number): boolean =>
20	  neighborCount === 3 || (isAlive && neighborCount === 2);
21	
22	export function nextGeneration(liveCells: Cell[]): Cell[] {
23	  const aliveKeys = new Set(liveCells.map(keyOf));
24	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
25	
26	  for (const [x, y] of liveCells) {
27	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
28	      const neighbor: Cell = [x + dx, y + dy];
29	      const entry = neighborCounts.get(keyOf(neighbor));
30	      if (entry) {
31	        entry.count++;
32	      } else {
33	        neighborCounts.set(keyOf(neighbor), { cell: neighbor, count: 1 });
34	      }
35	    }
36	  }
37	
38	  const nextLiveCells: Cell[] = [];
39	  for (const [k, { cell, count }] of neighborCounts) {
40	    if (survives(aliveKeys.has(k), count)) {
41	      nextLiveCells.push(cell);
42	    }
43	  }
44	  return nextLiveCells;
45	}
